_log = []
_initialized = False
_buffer = []


def reset():
    global _initialized
    _log.clear()
    _buffer.clear()
    _initialized = False


def init():
    global _initialized
    _initialized = True
    _log.append("init")
    while _buffer:
        item = _buffer.pop(0)
        _log.append(f"processed:{item}")


def process(item):
    """Accept items before init by buffering them until init runs."""
    if not _initialized:
        _buffer.append(item)
        _log.append(f"buffered:{item}")
        return True
    _log.append(f"processed:{item}")
    return True


def shutdown():
    _log.append("shutdown")
    return list(_log)


def get_log():
    return list(_log)


def run_steps(steps):
    results = []
    for fn, args in steps:
        results.append(fn(*args))
    return results


def correct_order():
    """init -> process(a) -> process(b) -> shutdown. Correct."""
    reset()
    run_steps([
        (init, ()),
        (process, ("a",)),
        (process, ("b",)),
        (shutdown, ()),
    ])
    return get_log()


def broken_order():
    """process(a) runs BEFORE init. BUG: item a is lost."""
    reset()
    run_steps([
        (process, ("a",)),
        (init, ()),
        (process, ("b",)),
        (shutdown, ()),
    ])
    return get_log()
